mapper.update:
update compile_job_steps
set status = 'succeeded',
    summary = #{summary},
    output_summary = #{outputSummary},
    error_message = null,
    finished_at = #{finishedAt}
where step_execution_id = #{stepExecutionId}
  and sequence_no = #{sequenceNo}

update compile_job_steps
set status = 'failed',
    summary = #{summary},
    error_message = #{errorMessage},
    finished_at = #{finishedAt}
where step_execution_id = #{stepExecutionId}
  and sequence_no = #{sequenceNo}
